import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long N = sc.nextLong();
            long M = sc.nextLong();
            if ((N * M) % 2 == 1) {
                System.out.println("Yes");
            } else {
                System.out.println("No");
            }
        }
    }
}

